import redis
import json
import os
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_nodes: list, password: str = None):
        self.redis_nodes = redis_nodes
        self.password = password
        self.redis_client = self._connect_to_cluster()
    
    def _connect_to_cluster(self) -> redis.Redis:
        try:
            # Create connection to the Redis cluster
            redis_cluster = redis.RedisCluster(
                startup_nodes=[redis.Node(node['host'], node['port']) for node in self.redis_nodes],
                password=self.password,
                decode_responses=True,
                socket_timeout=5,
                socket_connect_timeout=5,
                health_check_interval=30
            )
            return redis_cluster
        except Exception as e:
            raise Exception(f"Failed to connect to Redis cluster: {str(e)}")
    
    def set_session_token(self, user_id: str, token: str, ttl_minutes: int = 30) -> bool:
        try:
            key = f"user_session:{user_id}"
            ttl_seconds = ttl_minutes * 60
            self.redis_client.setex(key, ttl_seconds, token)
            return True
        except Exception as e:
            print(f"Error setting session token: {str(e)}")
            return False
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        try:
            key = f"user_session:{user_id}"
            return self.redis_client.get(key)
        except Exception as e:
            print(f"Error getting session token: {str(e)}")
            return None
    
    def delete_session_token(self, user_id: str) -> bool:
        try:
            key = f"user_session:{user_id}"
            return bool(self.redis_client.delete(key))
        except Exception as e:
            print(f"Error deleting session token: {str(e)}")
            return False
    
    def set_api_key(self, user_id: str, api_key: str, ttl_days: int = 30) -> bool:
        try:
            key = f"user_api_key:{user_id}"
            ttl_seconds = ttl_days * 24 * 60 * 60
            self.redis_client.setex(key, ttl_seconds, api_key)
            return True
        except Exception as e:
            print(f"Error setting API key: {str(e)}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        try:
            key = f"user_api_key:{user_id}"
            return self.redis_client.get(key)
        except Exception as e:
            print(f"Error getting API key: {str(e)}")
            return None
    
    def delete_api_key(self, user_id: str) -> bool:
        try:
            key = f"user_api_key:{user_id}"
            return bool(self.redis_client.delete(key))
        except Exception as e:
            print(f"Error deleting API key: {str(e)}")
            return False
    
    def set_cache(self, key: str, value: Any, ttl_seconds: int = 3600) -> bool:
        try:
            self.redis_client.setex(key, ttl_seconds, json.dumps(value))
            return True
        except Exception as e:
            print(f"Error setting cache: {str(e)}")
            return False
    
    def get_cache(self, key: str) -> Optional[Any]:
        try:
            value = self.redis_client.get(key)
            return json.loads(value) if value else None
        except Exception as e:
            print(f"Error getting cache: {str(e)}")
            return None

